diagram.d2:
direction: right
target: { label: "Target\nPR · commit · branch · working"; class: actor }
git: { label: "git.ts\nresolveScope · changedFiles" }
gitcli: { label: "git / gh"; class: external }
parse: { label: "parse-diff\nparseUnifiedDiff" }
order: { label: "diff-order\nsortByImportance" }
gather: { label: "gather-recap\nbuildBlocks → Block[]"; class: changed }
assemble: { label: "assemble-review\n+ src/review/*" }
html: { label: "recap.html"; class: store }
shared: { label: "assemble-atlas\nassemble-spec"; class: external }
target -> git
git -> gitcli: spawns
git -> parse: "unifiedDiff"
parse -> order: "DiffBlock[]"
order -> gather
git -> gather: "Scope · changedFiles"
gather -> assemble: "Block[]"
assemble -> html: render
shared -> assemble: "share css · helpers"

diagram.mermaid:
graph LR
  target["Target: PR / commit / branch / working"] --> git["git.ts: resolveScope, changedFiles"]
  git -->|spawns| gitcli["git / gh"]
  git -->|unifiedDiff| parse["parse-diff: parseUnifiedDiff"]
  parse -->|DiffBlock array| order["diff-order: sortByImportance"]
  order --> gather["gather-recap: buildBlocks -> Block array"]
  git -->|Scope, changedFiles| gather
  gather -->|Block array| assemble["assemble-review + src/review/*"]
  assemble -->|render| html["recap.html"]
  shared["assemble-atlas, assemble-spec"] -->|share css + helpers| assemble
  classDef changed fill:#ffd43b,stroke:#f08c00,color:#1b1b1b,stroke-width:2px;
  classDef actor fill:#d0ebff,stroke:#4dabf7,color:#1b1b1b;
  classDef external fill:#f1f3f5,stroke:#adb5bd,color:#1b1b1b;
  classDef store fill:#e5dbff,stroke:#9775fa,color:#1b1b1b;
  class gather changed;
  class target actor;
  class gitcli,shared external;
  class html store;

